// Extract JSON rows
const rows = $input.all().map(item => item.json);

// Fisher–Yates shuffle using Math.random()
for (let i = rows.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [rows[i], rows[j]] = [rows[j], rows[i]];
}

// Take first 10
const selected = rows.slice(0, 10);

// Build clean pairs
const pairs = selected.map(row => ({
  english: row["English word"],
  polish: row["Polish word"]
}));

return [{ json: { random_pairs: pairs } }];
